{
 "level": "B1",
 "intro": "In this topic, you will learn <strong>when to add \"by + agent\"</strong> in passive sentences, when it is better to omit it, and what is the difference between <strong>by</strong> and <strong>with</strong>.",
 "rules": [
 {
 "label": "Add by",
 "color": "emerald",
 "text": "When an artist is <strong>important or new</strong>:",
 "example": "The book was written by J.K. Rowling."
 },
 {
 "label": "Drop by",
 "color": "blue",
 "text": "When the performer is <strong>obvious or unknown</strong>:",
 "example": "He was arrested."
 },
 {
 "label": "by vs with",
 "color": "rose",
 "text": "<strong>by</strong> is the performer, <strong>with</strong> is the instrument:",
 "example": "The letter was written by Tom with a pen."
 }
 ]
}

{
 "title": "1. When to ADD \"by + agent\"",
 "sections": [
 {
 "label": "The performer is important",
 "color": "emerald",
 "description": "If the artist is <strong>key information</strong>, it must be specified.",
 "examples": [
 {
 "en": "The Mona Lisa was painted by Leonardo da Vinci.",
 "ua": "The Mona Lisa was painted by Leonardo da Vinci."
 },
 {
 "en": "This song was performed by Adele.",
 "ua": "This song was performed by Adele."
 },
 {
 "en": "The company was founded by Steve Jobs.",
 "ua": "The company was founded by Steve Jobs."
 }
 ]
 },
 {
 "label": "New information",
 "color": "sky",
 "description": "When the performer is <strong>new, unexpected information</strong> for the listener.",
 "examples": [
 {
 "en": "I was helped by a stranger.",
 "ua": "I was helped by a stranger."
 },
 {
 "en": "The window was broken by the kids next door.",
 "ua": "The window was broken by the kids next door."
 },
 {
 "en": "The project was completed by our junior team.",
 "ua": "The project was completed by our junior team."
 }
 ]
 },
 {
 "label": "Contrast/emphasis",
 "color": "amber",
 "description": "When we want to <strong>underline who exactly</strong> performed the action.",
 "examples": [
 {
 "en": "The report was written by me, not by Tom.",
 "ua": "The report was written by me, not by Tom."
 },
 {
 "en": "The cake was made by my grandmother.",
 "ua": "The cake was made by my grandmother."
 }
 ]
 }
 ]
}

{
 "title": "2. When to OMIT \"by + agent\"",
 "sections": [
 {
 "label": "The performer is obvious",
 "color": "emerald",
 "description": "When it is <strong>clear</strong> from the context who is performing the action.",
 "examples": [
 {
 "en": "He was arrested.",
 "ua": "He was arrested."
 },
 {
 "en": "The patient was operated on.",
 "ua": "The patient was operated on."
 },
 {
 "en": "The letter was delivered.",
 "ua": "The letter was delivered."
 }
 ]
 },
 {
 "label": "The performer is unknown",
 "color": "sky",
 "description": "We <strong>don't know</strong> who did the action.",
 "examples": [
 {
 "en": "My car was stolen.",
 "ua": "My car was stolen."
 },
 {
 "en": "The building was constructed in 1920.",
 "ua": "The building was constructed in 1920."
 },
 {
 "en": "The window was broken last night.",
 "ua": "The window was broken last night."
 }
 ]
 },
 {
 "label": "The performer is unimportant",
 "color": "amber",
 "description": "We <strong>don't care</strong> who performs the action. An important result.",
 "examples": [
 {
 "en": "English is spoken here.",
 "ua": "English is spoken here."
 },
 {
 "en": "The rules must be followed.",
 "ua": "The rules must be followed."
 },
 {
 "en": "The work will be finished tomorrow.",
 "ua": "The work will be finished tomorrow."
 }
 ]
 },
 {
 "label": "General executor",
 "color": "rose",
 "description": "When the performer is <strong>people in general</strong>: people, someone, they.",
 "examples": [
 {
 "en": "It is believed that... (people believe)",
 "ua": "It is believed that... (people believe)"
 },
 {
 "en": "The meeting was cancelled.",
 "ua": "The meeting was cancelled."
 }
 ]
 }
 ]
}

{
 "title": "3. \"by\" vs \"with\" — performer vs instrument",
 "sections": [
 {
 "label": "by — performer",
 "color": "emerald",
 "description": "<strong>by</strong> indicates the <strong>performer</strong> of the action (person, organization, force).",
 "examples": [
 {
 "en": "The letter was written by Tom.",
 "ua": "The letter was written by Tom."
 },
 {
 "en": "The house was destroyed by the earthquake.",
 "ua": "The house was destroyed by the earthquake."
 },
 {
 "en": "The decision was made by the committee.",
 "ua": "The decision was made by the committee."
 }
 ]
 },
 {
 "label": "with is a tool",
 "color": "blue",
 "description": "<strong>with</strong> indicates the <strong>tool or medium</strong> with which the action is performed.",
 "examples": [
 {
 "en": "The letter was written with a pen.",
 "ua": "The letter was written with a pen."
 },
 {
 "en": "The cake was decorated with cream.",
 "ua": "The cake was decorated with cream."
 },
 {
 "en": "The door was locked with a key.",
 "ua": "The door was locked with a key."
 }
 ]
 },
 {
 "label": "The combination of by + with",
 "color": "amber",
 "description": "You can use <strong>both</strong> in the same sentence.",
 "examples": [
 {
 "en": "The picture was painted by Monet with oil paints.",
 "ua": "The picture was painted by Monet with oil paints."
 },
 {
 "en": "The document was signed by the manager with a fountain pen.",
 "ua": "The document was signed by the manager with a fountain pen."
 }
 ]
 }
 ]
}

{
 "title": "4. Comparison: by vs with",
 "intro": "The key difference between by and with in passive sentences is:",
 "rows": [
 {
 "en": "by + agent",
 "ua": "by + agent",
 "note": "The book was written by J.K. Rowling."
 },
 {
 "en": "with + instrument",
 "ua": "with + instrument",
 "note": "The book was written with a pencil."
 },
 {
 "en": "by + natural force",
 "ua": "by + natural force",
 "note": "The tree was struck by lightning."
 },
 {
 "en": "with + material",
 "ua": "with + material",
 "note": "The house was built with bricks."
 }
 ],
 "warning": "📌 <strong>by</strong> = who/what caused the action. <strong>with</strong> = with which the action is performed."
}

{
 "title": "5. Typical mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Redundant \"by\" with obvious artist.",
 "wrong": "He was arrested by police.",
 "right": "✅ He was arrested."
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Confusion of by and with.",
 "wrong": "The letter was written with Tom.",
 "right": "✅ The letter was written by Tom."
 },
 {
 "label": "Error 3",
 "color": "sky",
 "title": "Using by instead of with for a tool.",
 "wrong": "The cake was cut by a knife.",
 "right": "✅ The cake was cut with a knife."
 },
 {
 "label": "Error 4",
 "color": "rose",
 "title": "Adding \"by someone/people\" is unnecessary.",
 "wrong": "English is spoken by people here.",
 "right": "✅ English is spoken here."
 }
 ]
}
